from series import double, fibonacci


def test_fibonacci_base_cases():
    assert fibonacci(0) == 0
    assert fibonacci(1) == 1


def test_fibonacci_later_values():
    assert fibonacci(6) == 8


def test_double():
    assert double(4) == 8

def fibonacci(n):
    if n <= 1:
        return 1  # BUG: fibonacci(0) should be 0
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a


def double(n):
    return n * 2
